// === INTERFACES ENTERPRISE OTIMIZADAS ===
interface CSVDataPoint {
  date: string;
  impressions: number;
  clicks: number;
  ctr: number;
  cpm: number;
  revenue: number;
  pageviews?: number;
  ad_requests?: number;
  coverage?: number;
}

interface ProcessedAnalysis {
  id?: string;
  site_id: string;
  analysis_type: 'csv_upload' | 'adsense_api' | 'manual';
  revenue_data: {
    total_revenue: number;
    avg_ctr: number;
    avg_cpm: number;
    avg_rpm: number;
    records_count: number;
    data_points: CSVDataPoint[];
    trending: {
      revenue_trend: number;
      ctr_trend: number;
      cpm_trend: number;
    };
    benchmarks: {
      industry_ctr: number;
      industry_cpm: number;
      industry_rpm: number;
    };
  };
  optimization_suggestions: string[];
  revenue_potential: number;
  optimization_score: number;
  confidence_level: number;
  niches_detected: string[];
  seasonality_factor: number;
  status: 'pending' | 'processing' | 'completed' | 'error';
  processing_time_ms?: number;
}

interface AnalysisValidation {
  isValid: boolean;
  errors: string[];
  warnings: string[];
  dataQuality: 'excellent' | 'good' | 'acceptable' | 'poor';
  completeness: number;
  consistency: number;
}

// === ANIMATION KEYFRAMES ENTERPRISE ===
const slideInRight = keyframes`
  from { opacity: 0; transform: translateX(24px) scale(0.98); }
  to { opacity: 1; transform: translateX(0) scale(1); }
`;

const processingPulse = keyframes`
  0%, 100% { box-shadow: 0 0 0 0 rgba(0, 122, 255, 0.4); }
  50% { box-shadow: 0 0 0 20px rgba(0, 122, 255, 0); }
`;

const successGlow = keyframes`
  0% { box-shadow: 0 2px 8px rgba(48, 209, 88, 0.2); }
  50% { box-shadow: 0 8px 32px rgba(48, 209, 88, 0.4); }
  100% { box-shadow: 0 2px 8px rgba(48, 209, 88, 0.2); }
`;

const dataFlowAnimation = keyframes`
  0% { transform: translateX(-100%); opacity: 0; }
  50% { opacity: 1; }
  100% { transform: translateX(100%); opacity: 0; }
`;

