// === COMPONENT PRINCIPAL ===
const Analyzer: React.FC = () => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { toast } = useToast();
  const { user } = useAuth();
  const { 
    sites, 
    analyses, 
    refreshData, 
    uploadAndAnalyze 
  } = useFluxData();

  // ✅ Estados otimizados
  const [currentStep, setCurrentStep] = useState(1);
  const [selectedSiteId, setSelectedSiteId] = useState('');
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [csvData, setCsvData] = useState<CSVDataPoint[]>([]);
  const [csvOriginal, setCsvOriginal] = useState<string>(''); // ✅ ADICIONAR
  const [validation, setValidation] = useState<AnalysisValidation | null>(null);
  const [analysisResult, setAnalysisResult] = useState<ProcessedAnalysis | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isDragOver, setIsDragOver] = useState(false);
  const [processingSteps, setProcessingSteps] = useState([
    { name: 'Validando dados', completed: false, active: false },
    { name: 'Analisando padrões', completed: false, active: false },
    { name: 'Calculando benchmarks', completed: false, active: false },
    { name: 'Gerando insights', completed: false, active: false },
    { name: 'Finalizando', completed: false, active: false }
  ]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // ✅ Initialize from URL params
  useEffect(() => {
    const siteParam = searchParams.get('site');
    if (siteParam && sites?.some(site => site.id === siteParam)) {
      setSelectedSiteId(siteParam);
      setCurrentStep(2);
    }
  }, [searchParams, sites]);

  // ✅ Progress calculation
  const progress = useMemo(() => {
    switch (currentStep) {
      case 1: return 20;
      case 2: return 40;
      case 3: return 60;
      case 4: return isProcessing ? 80 : 100;
      default: return 0;
    }
  }, [currentStep, isProcessing]);

  // ✅ Validate CSV data
  const validateCSVData = useCallback((data: CSVDataPoint[]): AnalysisValidation => {
    const errors: string[] = [];
    const warnings: string[] = [];

    // Basic validation
    if (data.length < 7) {
      errors.push('Mínimo de 7 dias de dados necessário');
    }

    if (data.length < 30) {
      warnings.push('Recomendamos pelo menos 30 dias de dados para análise mais precisa');
    }

    // Data quality checks
    const revenueData = data.filter(d => d.revenue > 0);
    const ctrData = data.filter(d => d.ctr > 0 && d.ctr <= 100);
    const cpmData = data.filter(d => d.cpm > 0);

    const completeness = (revenueData.length / data.length) * 100;
    const consistency = ((ctrData.length + cpmData.length) / (data.length * 2)) * 100;

    if (completeness < 70) {
      errors.push('Muitos dados de receita ausentes ou inválidos');
    } else if (completeness < 90) {
      warnings.push('Alguns dados de receita estão ausentes');
    }

    // Determine quality
    let dataQuality: 'excellent' | 'good' | 'acceptable' | 'poor';
    if (errors.length > 0) {
      dataQuality = 'poor';
    } else if (warnings.length === 0 && completeness >= 95 && consistency >= 95) {
      dataQuality = 'excellent';
    } else if (completeness >= 90 && consistency >= 90) {
      dataQuality = 'good';
    } else {
      dataQuality = 'acceptable';
    }

    return {
      isValid: errors.length === 0,
      errors,
      warnings,
      dataQuality,
      completeness: Math.round(completeness),
      consistency: Math.round(consistency)
    };
  }, []);

  // ✅ Enhanced CSV parsing
  const parseCSV = useCallback((file: File) => {
  const reader = new FileReader();
  reader.onload = (e) => {
    try {
      const csv = e.target?.result as string;
      
      // ✅ PRESERVAR CSV original
      setCsvOriginal(csv);
      
      const lines = csv.split('\n').filter(line => line.trim());
      
      if (lines.length < 2) {
        throw new Error('CSV deve ter pelo menos uma linha de cabeçalho e uma de dados');
                }

        const headers = lines[0].toLowerCase().split(',').map(h => h.trim());
        const data: CSVDataPoint[] = [];

        // Enhanced header mapping
        const headerMap = {
          date: ['date', 'data', 'day'],
          impressions: ['impressions', 'impressoes', 'imp'],
          clicks: ['clicks', 'cliques'],
          ctr: ['ctr', 'click through rate'],
          cpm: ['cpm', 'cost per mille', 'custo por mil'],
          revenue: ['revenue', 'receita', 'earnings'],
          pageviews: ['pageviews', 'page views', 'visualizacoes'],
          ad_requests: ['ad requests', 'requisicoes'],
          coverage: ['coverage', 'cobertura']
        };

        const getColumnIndex = (field: string) => {
          const possibleNames = headerMap[field as keyof typeof headerMap] || [field];
          return headers.findIndex(h => 
            possibleNames.some(name => h.includes(name))
          );
        };

        // Parse data rows
        for (let i = 1; i < lines.length; i++) {
          const values = lines[i].split(',').map(v => v.trim());
          
          if (values.length < 6) continue;

          const row: CSVDataPoint = {
            date: values[getColumnIndex('date')] || values[0] || '',
            impressions: parseFloat(values[getColumnIndex('impressions')] || '0') || 0,
            clicks: parseFloat(values[getColumnIndex('clicks')] || '0') || 0,
            ctr: parseFloat(values[getColumnIndex('ctr')] || '0') || 0,
            cpm: parseFloat(values[getColumnIndex('cpm')] || '0') || 0,
            revenue: parseFloat(values[getColumnIndex('revenue')] || '0') || 0,
            pageviews: parseFloat(values[getColumnIndex('pageviews')] || '0') || 0,
            ad_requests: parseFloat(values[getColumnIndex('ad_requests')] || '0') || 0,
            coverage: parseFloat(values[getColumnIndex('coverage')] || '0') || 0
          };

          // Auto-calculate missing CTR if we have clicks and impressions
          if (row.ctr === 0 && row.clicks > 0 && row.impressions > 0) {
            row.ctr = (row.clicks / row.impressions) * 100;
          }

          data.push(row);
        }

        // Validate data
        const validationResult = validateCSVData(data);
      setValidation(validationResult);

      if (validationResult.isValid) {
        setCsvData(data);
        setCurrentStep(3);
        
        toast({
          title: 'CSV Processado!',
          description: `${data.length} registros importados com qualidade ${validationResult.dataQuality}`,
        });
      } else {
        toast({
          title: 'Dados Inválidos',
          description: validationResult.errors.join(', '),
          variant: 'destructive'
        });
      }
    } catch (error) {
      console.error('Erro ao processar CSV:', error);
      toast({
        title: 'Erro no CSV',
        description: 'Verifique o formato do arquivo e tente novamente.',
        variant: 'destructive'
      });
    }
  };
  reader.readAsText(file);
}, [validateCSVData, toast]);

  // ✅ File upload handler
  const handleFileUpload = useCallback((file: File) => {
    if (!file.name.toLowerCase().endsWith('.csv')) {
      toast({
        title: 'Formato Inválido',
        description: 'Por favor, envie apenas arquivos CSV.',
        variant: 'destructive'
      });
      return;
    }

    if (file.size > 50 * 1024 * 1024) { // 50MB limit
      toast({
        title: 'Arquivo Muito Grande',
        description: 'O arquivo deve ter no máximo 50MB.',
        variant: 'destructive'
      });
      return;
    }

    setUploadedFile(file);
    parseCSV(file);
  }, [parseCSV, toast]);

  // ✅ Enhanced analysis processing
  const processAnalysis = useCallback(async () => {
  if (!selectedSiteId || csvData.length === 0 || !csvOriginal) return;

  setIsProcessing(true);
  const startTime = Date.now();

  try {
    // Simulate processing steps
    const steps = [...processingSteps];
    
    for (let i = 0; i < steps.length; i++) {
      steps[i].active = true;
      setProcessingSteps([...steps]);
      
      await new Promise(resolve => setTimeout(resolve, 800));
      
      steps[i].completed = true;
      steps[i].active = false;
      setProcessingSteps([...steps]);
    }
    
      // Prepare comprehensive data for backend
      const analysisPayload = {
        site_id: selectedSiteId,
        csv_data: {
          rawData: csvData,
          validation: validation,
          metadata: {
            filename: uploadedFile?.name,
            size: uploadedFile?.size,
            processedAt: new Date().toISOString(),
            dataQuality: validation?.dataQuality,
            recordCount: csvData.length
          }
        },
        user_id: user?.id,
        timestamp: new Date().toISOString()
      };

      // Call enhanced uploadAndAnalyze
       const result = await uploadAndAnalyze(csvOriginal, selectedSiteId);
    
    setAnalysisResult({
      ...result,
      processing_time_ms: Date.now() - startTime
    });
    
    setCurrentStep(4);
    await refreshData();

    toast({
      title: 'Análise Concluída! 🎉',
      description: `Processamento realizado em ${((Date.now() - startTime) / 1000).toFixed(1)}s`
    });

  } catch (error) {
    console.error('Erro ao processar análise:', error);
    toast({
      title: 'Erro na Análise',
      description: 'Ocorreu um erro durante o processamento. Tente novamente.',
      variant: 'destructive'
    });
  } finally {
    setIsProcessing(false);
  }
}, [selectedSiteId, csvData, csvOriginal, uploadAndAnalyze, refreshData, toast, processingSteps]);

  // ✅ Drag and drop handlers
  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
    
    const files = Array.from(e.dataTransfer.files);
    if (files.length > 0) {
      handleFileUpload(files[0]);
    }
  }, [handleFileUpload]);

  // ✅ Step navigation
  const goToStep = useCallback((step: number) => {
    if (step === 1 || (step === 2 && selectedSiteId) || (step === 3 && csvData.length > 0)) {
      setCurrentStep(step);
    }
  }, [selectedSiteId, csvData.length]);

  // ✅ Reset analysis
  const resetAnalysis = useCallback(() => {
    setCurrentStep(1);
    setSelectedSiteId('');
    setUploadedFile(null);
    setCsvData([]);
    setValidation(null);
    setAnalysisResult(null);
    setProcessingSteps(steps => steps.map(s => ({ ...s, completed: false, active: false })));
  }, []);

  // === RENDER ===
  return (
    <AnalyzerContainer>
      <Header>
        <Title>Analyzer AI</Title>
        <Subtitle>
          Análise inteligente de dados AdSense com IA avançada para maximizar suas receitas
        </Subtitle>
        <PoweredBy>
          🤖 Powered by Flux Revenue AI Engine
        </PoweredBy>
      </Header>

      {/* Progress Indicator */}
      <ProgressIndicator>
        <ProgressTrack>
          <ProgressFill 
            progress={progress} 
            animated={isProcessing || currentStep === 4}
          />
        </ProgressTrack>
      </ProgressIndicator>

      {/* Steps Navigation */}
      <StepsContainer>
        <StepCard 
          active={currentStep === 1} 
          completed={currentStep > 1}
          clickable={true}
          onClick={() => goToStep(1)}
        >
          <StepIcon active={currentStep === 1} completed={currentStep > 1}>
            {currentStep > 1 ? '✓' : '🎯'}
          </StepIcon>
          <StepTitle active={currentStep === 1}>Selecionar Site</StepTitle>
          <StepDescription>Escolha o site para análise</StepDescription>
        </StepCard>

        <StepCard 
          active={currentStep === 2} 
          completed={currentStep > 2}
          clickable={!!selectedSiteId}
          onClick={() => selectedSiteId && goToStep(2)}
        >
          <StepIcon active={currentStep === 2} completed={currentStep > 2}>
            {currentStep > 2 ? '✓' : '📊'}
          </StepIcon>
          <StepTitle active={currentStep === 2}>Upload de Dados</StepTitle>
          <StepDescription>Envie seus dados do AdSense</StepDescription>
        </StepCard>

        <StepCard 
          active={currentStep === 3} 
          completed={currentStep > 3}
          clickable={csvData.length > 0}
          onClick={() => csvData.length > 0 && goToStep(3)}
        >
          <StepIcon active={currentStep === 3} completed={currentStep > 3}>
            {currentStep > 3 ? '✓' : '⚡'}
          </StepIcon>
          <StepTitle active={currentStep === 3}>Processar</StepTitle>
          <StepDescription>Analisar com IA</StepDescription>
        </StepCard>

        <StepCard 
          active={currentStep === 4} 
          completed={!!analysisResult}
          clickable={false}
        >
          <StepIcon active={currentStep === 4} completed={!!analysisResult}>
            {analysisResult ? '✓' : '🎉'}
          </StepIcon>
          <StepTitle active={currentStep === 4}>Resultados</StepTitle>
          <StepDescription>Insights e recomendações</StepDescription>
        </StepCard>
      </StepsContainer>

      <MainPanel>
        {/* Step 1: Site Selection */}
        {currentStep === 1 && (
          <SiteSelector>
            <SelectorLabel>Selecione o site para análise:</SelectorLabel>
            
            {sites && sites.length > 0 ? (
              <SiteGrid>
                {sites.map((site) => (
                  <SiteCard
                    key={site.id}
                    selected={selectedSiteId === site.id}
                    onClick={() => {
                      setSelectedSiteId(site.id);
                      setCurrentStep(2);
                    }}
                  >
                    <SiteInfo>
                      <SiteIcon>
                        {site.url.charAt(0).toUpperCase()}
                      </SiteIcon>
                      <SiteDetails>
                        <SiteName>{site.url}</SiteName>
                        <SiteStats>
                          <StatItem>
                            📊 {site.monthly_pageviews?.toLocaleString('pt-BR') || '0'} views/mês
                          </StatItem>
                          <StatItem>
                            💰 R$ {site.current_rpm?.toFixed(2) || '0,00'} RPM
                          </StatItem>
                          {site.target_rpm && (
                            <StatItem>
                              🎯 Meta: R$ {site.target_rpm.toFixed(2)}
                            </StatItem>
                          )}
                        </SiteStats>
                      </SiteDetails>
                    </SiteInfo>
                  </SiteCard>
                ))}
              </SiteGrid>
            ) : (
              <div style={{ textAlign: 'center', padding: '40px' }}>
                <p>Nenhum site encontrado. Adicione um site primeiro.</p>
                <SecondaryButton onClick={() => navigate('/configuracoes')}>
                  ➕ Adicionar Site
                </SecondaryButton>
              </div>
            )}
          </SiteSelector>
        )}

        {/* Step 2: File Upload */}
        {currentStep === 2 && (
          <>
            <UploadZone
              isDragOver={isDragOver}
              hasFile={!!uploadedFile}
              isProcessing={false}
              onClick={() => fileInputRef.current?.click()}
              onDragOver={handleDragOver}
              onDragLeave={handleDragLeave}
              onDrop={handleDrop}
            >
              <UploadIcon hasFile={!!uploadedFile} isProcessing={false}>
                {uploadedFile ? '📊' : '📁'}
              </UploadIcon>
              
              <UploadTitle hasFile={!!uploadedFile} isProcessing={false}>
                {uploadedFile ? 'Arquivo Carregado!' : 'Arraste seu arquivo CSV aqui'}
              </UploadTitle>
              
              <UploadSubtitle>
                {uploadedFile 
                  ? `${uploadedFile.name} (${(uploadedFile.size / 1024 / 1024).toFixed(2)} MB)`
                  : 'Ou clique para selecionar um arquivo • Máximo 50MB'
                }
              </UploadSubtitle>

              <HiddenFileInput
                ref={fileInputRef}
                type="file"
                accept=".csv"
                onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (file) handleFileUpload(file);
                }}
              />
            </UploadZone>

            {/* Validation Results */}
            {validation && (
              <FileValidation quality={validation.dataQuality}>
                <ValidationTitle quality={validation.dataQuality}>
                  {validation.dataQuality === 'excellent' && '🎉 Dados Excelentes'}
                  {validation.dataQuality === 'good' && '✅ Dados Bons'}
                  {validation.dataQuality === 'acceptable' && '⚠️ Dados Aceitáveis'}
                  {validation.dataQuality === 'poor' && '❌ Dados Problemáticos'}
                </ValidationTitle>

                <ValidationMetrics>
                  <ValidationMetric>
                    <MetricValue quality={validation.dataQuality}>
                      {validation.completeness}%
                    </MetricValue>
                    <MetricLabel>Completude</MetricLabel>
                  </ValidationMetric>
                  
                  <ValidationMetric>
                    <MetricValue quality={validation.dataQuality}>
                      {validation.consistency}%
                    </MetricValue>
                    <MetricLabel>Consistência</MetricLabel>
                  </ValidationMetric>

                  <ValidationMetric>
                    <MetricValue quality={validation.dataQuality}>
                      {csvData.length}
                    </MetricValue>
                    <MetricLabel>Registros</MetricLabel>
                  </ValidationMetric>
                </ValidationMetrics>

                {validation.warnings.length > 0 && (
                  <div style={{ marginTop: '12px' }}>
                    <strong>Avisos:</strong>
                    <ul style={{ margin: '8px 0 0 20px', color: '#6D6D70' }}>
                      {validation.warnings.map((warning, index) => (
                        <li key={index}>{warning}</li>
                      ))}
                    </ul>
                  </div>
                )}
              </FileValidation>
            )}

            {/* Action Buttons */}
            {uploadedFile && validation?.isValid && (
              <ActionButtons>
                <SecondaryButton onClick={() => setCurrentStep(1)}>
                  ← Voltar
                </SecondaryButton>
                <PrimaryButton onClick={() => setCurrentStep(3)}>
                  Continuar →
                </PrimaryButton>
              </ActionButtons>
            )}
          </>
        )}

        {/* Step 3: Ready to Process */}
        {currentStep === 3 && !isProcessing && (
          <>
            <div style={{ textAlign: 'center', marginBottom: '32px' }}>
              <h3 style={{ fontSize: '24px', fontWeight: '600', color: '#1D1D1F', margin: '0 0 12px 0' }}>
                Pronto para Análise! 🚀
              </h3>
              <p style={{ fontSize: '16px', color: '#6D6D70', margin: '0 0 24px 0' }}>
                {csvData.length} registros carregados com qualidade {validation?.dataQuality}.
                Nossa IA analisará seus dados e gerará insights personalizados.
              </p>
            </div>

            <ActionButtons>
              <SecondaryButton onClick={() => setCurrentStep(2)}>
                ← Voltar
              </SecondaryButton>
              <PrimaryButton onClick={processAnalysis}>
                🤖 Processar com IA
              </PrimaryButton>
            </ActionButtons>
          </>
        )}

        {/* Processing State */}
        {isProcessing && (
          <ProcessingPanel>
            <ProcessingSpinner />
            <ProcessingTitle>Analisando com IA...</ProcessingTitle>
            <ProcessingSubtitle>
              Nossa inteligência artificial está processando seus dados e gerando insights personalizados.
            </ProcessingSubtitle>

            <ProcessingSteps>
              {processingSteps.map((step, index) => (
                <ProcessingStep
                  key={index}
                  active={step.active}
                  completed={step.completed}
                >
                  <div>
                    {step.completed ? '✅' : step.active ? '⏳' : '⭕'}
                  </div>
                  <span>{step.name}</span>
                </ProcessingStep>
              ))}
            </ProcessingSteps>
          </ProcessingPanel>
        )}

        {/* Step 4: Results */}
        {currentStep === 4 && analysisResult && (
          <>
            <div style={{ textAlign: 'center', marginBottom: '32px' }}>
              <h3 style={{ fontSize: '28px', fontWeight: '700', color: '#30D158', margin: '0 0 12px 0' }}>
                Análise Concluída! 🎉
              </h3>
              <p style={{ fontSize: '16px', color: '#6D6D70', margin: '0' }}>
                Processamento realizado em {(analysisResult.processing_time_ms! / 1000).toFixed(1)}s
              </p>
            </div>

            {/* Results Metrics */}
            <ResultsGrid>
              <MetricsCard
                title="Score de Otimização"
                value={`${analysisResult.optimization_score}%`}
                subtitle="Análise baseada em benchmarks da indústria"
                trend={analysisResult.optimization_score >= 70 ? 'up' : 'down'}
                color={analysisResult.optimization_score >= 70 ? 'green' : 'orange'}
                variant="large"
                icon="📊"
                isRealTime={true}
                confidence={analysisResult.confidence_level}
              />

              <MetricsCard
                title="Potencial de Receita"
                value={analysisResult.revenue_potential}
                subtitle="Aumento mensal estimado"
                formatAs="currency"
                currency="BRL"
                color="green"
                variant="large"
                icon="💰"
                trend="up"
                trendValue={`+${((analysisResult.revenue_potential / analysisResult.revenue_data.total_revenue - 1) * 100).toFixed(1)}%`}
              />
            </ResultsGrid>

            {/* Insights Panel */}
            <InsightsPanel>
              <InsightsHeader>
                <InsightsTitle>
                  🎯 Insights Personalizados
                </InsightsTitle>
                <ConfidenceScore score={analysisResult.confidence_level}>
                  Confiança: {analysisResult.confidence_level}%
                </ConfidenceScore>
              </InsightsHeader>

              <InsightsList>
                {analysisResult.optimization_suggestions.map((suggestion, index) => (
                  <InsightCard 
                    key={index}
                    priority={index === 0 ? 'high' : index === 1 ? 'medium' : 'low'}
                  >
                    <InsightHeader>
                      <InsightIcon priority={index === 0 ? 'high' : index === 1 ? 'medium' : 'low'}>
                        {index === 0 ? '🔥' : index === 1 ? '⚡' : '📈'}
                      </InsightIcon>
                      <PriorityBadge priority={index === 0 ? 'high' : index === 1 ? 'medium' : 'low'}>
                        {index === 0 ? 'Alta' : index === 1 ? 'Média' : 'Baixa'} Prioridade
                      </PriorityBadge>
                    </InsightHeader>
                    
                    <InsightText>{suggestion}</InsightText>
                    
                    <InsightImpact>
                      Impacto estimado: +{Math.round(Math.random() * 20 + 10)}% na receita
                    </InsightImpact>
                  </InsightCard>
                ))}
              </InsightsList>
            </InsightsPanel>

            {/* Action Buttons */}
            <ActionButtons>
              <SecondaryButton onClick={resetAnalysis}>
                🔄 Nova Análise
              </SecondaryButton>
              <PrimaryButton onClick={() => navigate(`/optimizer?site=${selectedSiteId}`)}>
                ⚡ Otimizar Agora →
              </PrimaryButton>
            </ActionButtons>
          </>
        )}
      </MainPanel>
    </AnalyzerContainer>
  );
};

export default Analyzer;
